var ctx=cnv.getContext("2d"),W=window.innerWidth,H=window.innerHeight;function animate(){ctx.beginPath(),ctx.fillStyle="white",ctx.arc(W*Math.random(),H*Math.random(),2.5*Math.random(),0,2*Math.PI),ctx.fill(),setTimeout(animate,100)}cnv.width=W,cnv.height=H,ctx.fillStyle="#112",ctx.fillRect(0,0,W,H),(background=new Image).src="https://srkibro.github.io/images/bg.webp",background.onload=function(){ctx.drawImage(background,0,0,cnv.width,cnv.height)},ctx.shadowBlur=10,ctx.shadowColor="white";